// ---------------------------------------------------------------
import { useState, useEffect } from 'react';

function Home() {
  const [mousePosition, setMousePosition] = useState({ x: 0, y: 0 });

  // Handler para el movimiento del mouse
  const handleMouseMove = (e: any) => {
    const { left, top, width, height } = e.target.getBoundingClientRect();
    const mouseX = e.clientX - left;
    const mouseY = e.clientY - top;
    setMousePosition({ x: mouseX, y: mouseY });
  };

  // Reaccionar al movimiento del mouse sobre el contenedor
  useEffect(() => {
    const container = document.querySelector('.ml-40');
    container?.addEventListener('mousemove', handleMouseMove);

    return () => {
      container?.removeEventListener('mousemove', handleMouseMove);
    };
  }, []);

  const moveImage = (axis: any, position: any) => {
    const maxOffset = 10; // Radio máximo de movimiento en px
    const center = axis === 'x' ? 150 : 150; // Centro de las imágenes (puedes ajustarlo según tus necesidades)
    const offset =
      (axis === 'x' ? mousePosition.x - center : mousePosition.y - center) /
      100;
    return position + maxOffset * offset;
  };

  return (
    <div className="w-full h-[100vh] flex items-center justify-center p-10 relative">
      <div
        className="absolute top-0 left-0 w-full h-full"
        style={{
          backgroundImage: "url('/fondo6.jpg')",
          backgroundSize: 'cover',
          backgroundPosition: 'center',
          opacity: 0.4,
        }}
      />
      <div className="w-full h-full z-10 flex items-center justify-between">
        {/* Images left */}
        <div className="h-full relative flex items-center">
          <div className="ml-40 relative">
            {/* Primera imagen */}
            <img
              className="rounded-lg transition-transform transform"
              width={300}
              height={250}
              src="/Foto3.HEIC"
              alt="Imagen 1"
            />
            {/* Segunda imagen (centrada arriba, deslizada a la izquierda) */}
            <img
              className="rounded-lg absolute transition-transform transform hover:scale-110"
              width={150}
              height={150}
              style={{
                top: `calc(50% - 75px)`, // Centrada verticalmente con la primera imagen
                left: `calc(50% - 75px - 20px)`, // Deslizada a la izquierda
              }}
              src="/Foto1.HEIC"
              alt="Imagen 2"
            />
            {/* Tercera imagen (centrada arriba, deslizada más abajo) */}
            <img
              className="rounded-lg absolute transition-transform transform hover:scale-110"
              width={150}
              height={150}
              style={{
                top: `calc(85%)`, // Deslizada más abajo con respecto a la primera imagen
                left: `calc(50% - 75px)`, // Centrada horizontalmente
              }}
              src="/Foto4.HEIC"
              alt="Imagen 3"
            />
          </div>
        </div>
        {/* Text center */}
        <div className="h-full flex flex-col justify-center items-center gap-5">
          <h3 className="text-[#6d7561] md:text-2xl font-medium text-center">
            ¡Los invitamos a festejar nuestra boda!
          </h3>
          <h1 className="text-[#6d7561] text-4xl md:text-4xl font-bold text-center">
            Anto & Kevin
          </h1>
          <a
            href="#ConfirmAttendance"
            className="text-[#6d7561] text-2xl underline hover:text-[#6d756190]"
          >
            {`Confirmar asistencia ${'>'}`}
          </a>
        </div>
        {/* Images right */}
        <div className="h-full relative flex items-center justify-end">
          <div className="mr-40 relative">
            <img
              className="rounded-lg transition-transform transform hover:scale-110"
              width={300}
              height={250}
              src="/Foto3.HEIC"
              alt="Imagen 1"
            />
            <img
              className="rounded-lg absolute -right-28 transition-transform transform hover:scale-110"
              width={150}
              height={150}
              style={{
                top: 'calc(50% - 75px)',
              }}
              src="/Foto1.HEIC"
              alt="Imagen 2"
            />
          </div>
        </div>
      </div>
    </div>
  );
}

export default Home;
